function renderPreloadedExercisePresentations(){
  const grid = document.getElementById("exercisePresentationsGrid");
  if(!grid) return;

  grid.innerHTML = preloadedExercisePresentations.map((file) => {
    const safeTitle = String(file.title).replace(/'/g, "\'");
    const icon = file.type === "JPG" || file.type === "JPEG" || file.type === "PNG" ? "🖼️" : "📄";
    return `
      <button class="exercise-thumb-card" onclick="openFilePreview('${safeTitle}', '${file.url}')">
        <div class="exercise-thumb">
          <span>${icon}</span>
          <small>${file.type}</small>
        </div>
        <div class="exercise-thumb-text">
          <strong>${file.title}</strong>
          <span>${file.original}</span>
        </div>
      </button>
    `;
  }).join("");
}

