let selectedWeatherAirport = "LHKA";

function selectWeatherAirport(icao){
  selectedWeatherAirport = icao;
  document.querySelectorAll(".weather-airport-tab").forEach(tab => {
    tab.classList.toggle("active", tab.dataset.icao === icao);
  });
  const data = weatherAirportData[icao];
  document.getElementById("weatherAirportChip").textContent = icao;
  document.getElementById("weatherAirportName").textContent = data.name;
  document.getElementById("metarTafLink").href = data.metarTaf;
  loadSelectedAirportWeather();
}

async function loadSelectedAirportWeather(){
  const icao = selectedWeatherAirport;
  const metarBox = document.getElementById("airportMetarBox");
  const tafBox = document.getElementById("airportTafBox");
  const summary = document.getElementById("airportWeatherSummary");
  if(!metarBox || !tafBox || !summary) return;

  metarBox.textContent = "Loading METAR...";
  tafBox.textContent = "Loading TAF...";
  summary.innerHTML = "<p>Loading general weather information...</p>";

  try{
    const res = await fetch(`/api/weather/airport/${encodeURIComponent(icao)}`);
    const data = await res.json();
    if(!res.ok) throw new Error(data.detail || "Weather fetch failed");

    metarBox.textContent = data.metar || `No public METAR returned for ${icao}. Open the METAR-TAF page.`;
    tafBox.textContent = data.taf || `No public TAF returned for ${icao}. Open the METAR-TAF page.`;

    const s = data.summary || {};
    summary.innerHTML = `
      <div class="weather-summary-item"><span>Source airport used</span><strong>${data.source_airport || "N/A"}</strong></div>
      <div class="weather-summary-item"><span>Temperature</span><strong>${s.temperature ?? "N/A"}</strong></div>
      <div class="weather-summary-item"><span>Pressure</span><strong>${s.pressure ?? "N/A"}</strong></div>
      <div class="weather-summary-item"><span>Wind</span><strong>${s.wind ?? "N/A"}</strong></div>
      <div class="weather-summary-item"><span>Visibility</span><strong>${s.visibility ?? "N/A"}</strong></div>
      <div class="weather-summary-item"><span>Clouds</span><strong>${s.clouds ?? "N/A"}</strong></div>
      <div class="weather-summary-item"><span>Nearby fallback</span><strong>${data.used_fallback ? "Yes" : "No"}</strong></div>
    `;
  }catch(err){
    metarBox.textContent = `Could not load METAR for ${icao}.`;
    tafBox.textContent = `Could not load TAF for ${icao}.`;
    summary.innerHTML = `<p>${err.message}. Use the METAR-TAF button as fallback.</p>`;
  }
}

function openFilePreview(title, url){
  document.getElementById("filePreviewTitle").textContent = title;
  document.getElementById("filePreviewOpen").href = url;
  document.getElementById("filePreviewFrame").src = url;
  document.getElementById("filePreviewModal").classList.remove("hidden");
}
function closeFilePreview(){
  document.getElementById("filePreviewFrame").src = "";
  document.getElementById("filePreviewModal").classList.add("hidden");
}

function showAircraftTopic(id){
  document.querySelectorAll(".aircraft-topic").forEach(el => el.classList.remove("active"));
  const topic = document.getElementById("topic-" + id);
  if(topic) topic.classList.add("active");

  document.querySelectorAll(".study-menu button").forEach(btn => {
    btn.classList.toggle("active", btn.dataset.topic === id);
  });
}


let atplAiSettings = { url: "https://avioren-aviation-mvp.onrender.com/", active: false };

async function loadAtplAiSettings(){
  try{
    const res = await fetch("/api/settings/atpl-ai");
    const data = await res.json();
    if(res.ok){
      atplAiSettings = {
        url: data.url || atplAiSettings.url,
        active: !!data.active
      };
      const urlInput = document.getElementById("atplAiUrlInput");
      const activeInput = document.getElementById("atplAiActiveInput");
      if(urlInput) urlInput.value = atplAiSettings.url;
      if(activeInput) activeInput.checked = atplAiSettings.active;
    }
  }catch(err){
    // keep defaults
  }
}

async function saveAtplAiSettings(e){
  e.preventDefault();
  try{
    const form = e.target;
    const fd = new FormData();
    fd.append("url", form.url.value);
    fd.append("active", form.active.checked ? "true" : "false");
    const res = await fetch("/api/settings/atpl-ai", {
      method: "POST",
      headers: authHeaders(),
      body: fd
    });
    const data = await res.json().catch(()=>({}));
    if(!res.ok) throw new Error(data.detail || "Could not save ATPL AI settings");
    atplAiSettings = {url: data.url, active: !!data.active};
    toast("ATPL AI settings saved");
  }catch(err){
    toast(err.message);
  }
}

async function handleAtplAiClick(event){
  if(event){ event.preventDefault(); event.stopPropagation(); }
  await loadAtplAiSettings();
  if(atplAiSettings.active){
    window.open(atplAiSettings.url || "https://avioren-aviation-mvp.onrender.com/", "_blank", "noopener");
  }else{
    showPage("atplai");
  }
}

document.addEventListener("DOMContentLoaded", () => {
  const form = document.getElementById("atplAiSettingsForm");
  if(form) form.addEventListener("submit", saveAtplAiSettings);
  loadAtplAiSettings();
});


function showBriefingTab(tab){
  document.querySelectorAll(".briefing-tab").forEach(btn => btn.classList.toggle("active", btn.dataset.briefingTab === tab));
  document.querySelectorAll(".briefing-tab-panel").forEach(panel => panel.classList.remove("active"));
  const panel = document.getElementById("briefingTab-" + tab);
  if(panel) panel.classList.add("active");

  if(tab === "weather") loadSelectedAirportWeather();
  if(tab === "notam") loadNotam();
  if(tab === "exercises") renderPreloadedExercisePresentations();
}


async function loadNotam(){
  const select = document.getElementById("notamAirportSelect");
  const output = document.getElementById("notamOutput");
  const title = document.getElementById("notamTitle");
  const official = document.getElementById("notamOfficialLink");
  if(!select || !output || !title) return;

  const icao = select.value || "LHKE";
  title.textContent = `${icao} NOTAM`;
  output.textContent = "Loading NOTAM...";
  if(official) official.href = `https://www.notams.faa.gov/dinsQueryWeb/queryRetrievalMapAction.do?reportType=Raw&retrieveLocId=${encodeURIComponent(icao)}`;

  try{
    const res = await fetch(`/api/notam/${encodeURIComponent(icao)}`);
    const data = await res.json();
    if(!res.ok) throw new Error(data.detail || "NOTAM fetch failed");
    output.textContent = data.notams || `No NOTAM returned for ${icao}. Use the official NOTAM search link.`;
  }catch(err){
    output.textContent = `${err.message}\n\nUse the official NOTAM search link.`;
  }
}
